#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MG_DIR ".minigit"
#define MG_INDEX MG_DIR "/index"
#define MG_OBJECTS MG_DIR "/objects"
#define MG_REFS MG_DIR "/refs"
#define MG_REFS_HEADS MG_REFS "/heads"
#define MG_HEAD MG_DIR "/HEAD"
#define MG_CONFIG MG_DIR "/config"
#define MG_DESCRIPTION MG_DIR "/description"
#define MG_IGNORE MG_DIR "/ignore"

#define MAX_PATH 1024
#define MAX_LINE 1024
#define MAX_FILES 1024
#define MAX_COMMITS 1024

typedef struct {
    char path[MAX_PATH];
    char hash[41];
} IndexEntry;

typedef struct {
    IndexEntry entries[MAX_FILES];
    int count;
} Index;

typedef struct {
    char hash[41];
    char parent[41];
    char message[MAX_LINE];
    time_t timestamp;
} Commit;

static void die(const char *msg) {
    perror(msg);
    exit(1);
}

static void mkdir_p(const char *dir) {
    char tmp[MAX_PATH];
    char *p = NULL;
    size_t len;
    snprintf(tmp, sizeof(tmp), "%s", dir);
    len = strlen(tmp);
    if (tmp[len - 1] == '/') tmp[len - 1] = 0;
    for (p = tmp; *p; p++) {
        if (*p == '/') {
            *p = 0;
            mkdir(tmp, 0755);
            *p = '/';
        }
    }
    mkdir(tmp, 0755);
}

static void sha1_file(const char *path, char *out) {
    FILE *f = fopen(path, "rb");
    if (!f) die("fopen");
    unsigned char hash[20];
    SHA1_CTX ctx;
    SHA1Init(&ctx);
    char buf[4096];
    size_t n;
    while ((n = fread(buf, 1, sizeof(buf), f)) > 0) {
        SHA1Update(&ctx, (unsigned char *)buf, n);
    }
    SHA1Final(hash, &ctx);
    fclose(f);
    for (int i = 0; i < 20; i++) {
        sprintf(out + i * 2, "%02x", hash[i]);
    }
}

static void sha1_data(const void *data, size_t len, char *out) {
    unsigned char hash[20];
    SHA1_CTX ctx;
    SHA1Init(&ctx);
    SHA1Update(&ctx, (unsigned char *)data, len);
    SHA1Final(hash, &ctx);
    for (int i = 0; i < 20; i++) {
        sprintf(out + i * 2, "%02x", hash[i]);
    }
}

static void read_index(Index *index) {
    index->count = 0;
    FILE *f = fopen(MG_INDEX, "r");
    if (!f) return;
    char line[MAX_LINE];
    while (fgets(line, sizeof(line), f)) {
        line[strcspn(line, "\n")] = 0;
        char *space = strchr(line, ' ');
        if (!space) continue;
        *space = 0;
        strcpy(index->entries[index->count].path, line);
        strcpy(index->entries[index->count].hash, space + 1);
        index->count++;
    }
    fclose(f);
}

static void write_index(const Index *index) {
    FILE *f = fopen(MG_INDEX, "w");
    if (!f) die("fopen");
    for (int i = 0; i < index->count; i++) {
        fprintf(f, "%s %s\n", index->entries[i].path, index->entries[i].hash);
    }
    fclose(f);
}

static int index_find(const Index *index, const char *path) {
    for (int i = 0; i < index->count; i++) {
        if (strcmp(index->entries[i].path, path) == 0) return i;
    }
    return -1;
}

static void index_add(Index *index, const char *path, const char *hash) {
    int pos = index_find(index, path);
    if (pos >= 0) {
        strcpy(index->entries[pos].hash, hash);
    } else {
        strcpy(index->entries[index->count].path, path);
        strcpy(index->entries[index->count].hash, hash);
        index->count++;
    }
}

static void index_remove(Index *index, const char *path) {
    int pos = index_find(index, path);
    if (pos < 0) return;
    for (int i = pos; i < index->count - 1; i++) {
        index->entries[i] = index->entries[i + 1];
    }
    index->count--;
}

static void copy_file(const char *src, const char *dst) {
    FILE *s = fopen(src, "rb");
    if (!s) die("fopen src");
    FILE *d = fopen(dst, "wb");
    if (!d) die("fopen dst");
    char buf[4096];
    size_t n;
    while ((n = fread(buf, 1, sizeof(buf), s)) > 0) {
        fwrite(buf, 1, n, d);
    }
    fclose(s);
    fclose(d);
}

static void write_object(const char *hash, const void *data, size_t len) {
    char path[MAX_PATH];
    snprintf(path, sizeof(path), "%s/%c%c/%s", MG_OBJECTS, hash[0], hash[1], hash + 2);
    mkdir_p(path);
    FILE *f = fopen(path, "wb");
    if (!f) die("fopen object");
    fwrite(data, 1, len, f);
    fclose(f);
}

static int read_object(const char *hash, void *data, size_t *len) {
    char path[MAX_PATH];
    snprintf(path, sizeof(path), "%s/%c%c/%s", MG_OBJECTS, hash[0], hash[1], hash + 2);
    FILE *f = fopen(path, "rb");
    if (!f) return -1;
    *len = fread(data, 1, *len, f);
    fclose(f);
    return 0;
}

static void write_index_to_tree(char *out) {
    Index index;
    read_index(&index);
    char tree_data[MAX_FILES * MAX_LINE];
    int offset = 0;
    for (int i = 0; i < index.count; i++) {
        int n = snprintf(tree_data + offset, sizeof(tree_data) - offset, "%s %s\n", index.entries[i].path, index.entries[i].hash);
        offset += n;
    }
    sha1_data(tree_data, offset, out);
    write_object(out, tree_data, offset);
}

static void update_ref(const char *ref, const char *hash) {
    char path[MAX_PATH];
    if (strncmp(ref, "refs/heads/", 11) == 0) {
        snprintf(path, sizeof(path), "%s/%s", MG_REFS_HEADS, ref + 11);
    } else {
        snprintf(path, sizeof(path), "%s", ref);
    }
    FILE *f = fopen(path, "w");
    if (!f) die("fopen ref");
    fprintf(f, "%s\n", hash);
    fclose(f);
}

static const char *resolve_ref(const char *ref) {
    static char hash[41];
    char path[MAX_PATH];
    if (strncmp(ref, "refs/heads/", 11) == 0) {
        snprintf(path, sizeof(path), "%s/%s", MG_REFS_HEADS, ref + 11);
    } else {
        snprintf(path, sizeof(path), "%s", ref);
    }
    FILE *f = fopen(path, "r");
    if (!f) return NULL;
    if (!fgets(hash, sizeof(hash), f)) hash[0] = 0;
    fclose(f);
    hash[strcspn(hash, "\n")] = 0;
    return hash[0] ? hash : NULL;
}

static const char *get_head() {
    static char ref[MAX_PATH];
    FILE *f = fopen(MG_HEAD, "r");
    if (!f) return NULL;
    if (!fgets(ref, sizeof(ref), f)) ref[0] = 0;
    fclose(f);
    ref[strcspn(ref, "\n")] = 0;
    if (strncmp(ref, "ref: ", 5) == 0) return resolve_ref(ref + 5);
    return ref[0] ? ref : NULL;
}

static void set_head_ref(const char *ref) {
    FILE *f = fopen(MG_HEAD, "w");
    if (!f) die("fopen HEAD");
    fprintf(f, "ref: %s\n", ref);
    fclose(f);
}

static void read_commit(const char *hash, Commit *commit) {
    char data[MAX_LINE * 4];
    size_t len = sizeof(data);
    if (read_object(hash, data, &len) < 0) die("read_object commit");
    data[len] = 0;
    char *p = data;
    char *line = strtok(p, "\n");
    strcpy(commit->hash, hash);
    line = strtok(NULL, "\n");
    if (line && strncmp(line, "parent ", 7) == 0) strcpy(commit->parent, line + 7);
    else commit->parent[0] = 0;
    line = strtok(NULL, "\n");
    if (line && strncmp(line, "date ", 5) == 0) commit->timestamp = atol(line + 5);
    line = strtok(NULL, "\");
    if (line) strcpy(commit->message, line);
}

static void write_commit(const char *parent, const char *message, char *out) {
    char tree_hash[41];
    write_index_to_tree(tree_hash);
    char commit_data[MAX_LINE * 4];
    int n = snprintf(commit_data, sizeof(commit_data), "tree %s\n", tree_hash);
    if (parent && parent[0]) n += snprintf(commit_data + n, sizeof(commit_data) - n, "parent %s\n", parent);
    time_t now = time(NULL);
    n += snprintf(commit_data + n, sizeof(commit_data) - n, "date %ld\n", now);
    n += snprintf(commit_data + n, sizeof(commit_data) - n, "%s\n", message);
    sha1_data(commit_data, n, out);
    write_object(out, commit_data, n);
}

static void checkout_commit(const char *hash) {
    char data[MAX_FILES * MAX_LINE];
    size_t len = sizeof(data);
    if (read_object(hash, data, &len) < 0) die("read_object tree");
    char *p = data;
    char *line;
    while ((line = strtok(p, "\n")) != NULL) {
        p = NULL;
        char *space = strchr(line, ' ');
        if (!space) continue;
        *space = 0;
        const char *path = line;
        const char *obj_hash = space + 1;
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), "%s/%c%c/%s", MG_OBJECTS, obj_hash[0], obj_hash[1], obj_hash + 2);
        copy_file(obj_path, path);
    }
}

static void cmd_init(int argc, char **argv) {
    mkdir_p(MG_OBJECTS);
    mkdir_p(MG_REFS_HEADS);
    FILE *f = fopen(MG_HEAD, "w");
    if (!f) die("fopen HEAD");
    fprintf(f, "ref: refs/heads/master\n");
    fclose(f);
    f = fopen(MG_CONFIG, "w");
    if (!f) die("fopen config");
    fclose(f);
    f = fopen(MG_DESCRIPTION, "w");
    if (!f) die("fopen description");
    fprintf(f, "Unnamed repository\n");
    fclose(f);
}

static void cmd_add(int argc, char **argv) {
    if (argc < 1) die("usage: minigit add <file>");
    Index index;
    read_index(&index);
    for (int i = 0; i < argc; i++) {
        char hash[41];
        sha1_file(argv[i], hash);
        char obj_path[MAX_PATH];
        snprintf(obj_path, sizeof(obj_path), "%s/%c%c/%s", MG_OBJECTS, hash[0], hash[1], hash + 2);
        mkdir_p(obj_path);
        copy_file(argv[i], obj_path);
        index_add(&index, argv[i], hash);
    }
    write_index(&index);
}

static void cmd_commit(int argc, char **argv) {
    char *message = NULL;
    for (int i = 0; i < argc; i++) {
        if (strcmp(argv[i], "-m") == 0 && i + 1 < argc) {
            message = argv[i + 1];
            break;
        }
    }
    if (!message) die("usage: minigit commit -m <message>");
    const char *head = get_head();
    char commit_hash[41];
    write_commit(head, message, commit_hash);
    update_ref("refs/heads/master", commit_hash);
}

static void cmd_checkout(int argc, char **argv) {
    if (argc < 1) die("usage: minigit checkout <ref>");
    const char *ref = resolve_ref(argv[0]);
    if (!ref) ref = argv[0];
    checkout_commit(ref);
    set_head_ref(argv[0]);
}

static void cmd_reset(int argc, char **argv) {
    if (argc < 1) die("usage: minigt reset <ref>");
    const char *ref = resolve_ref(argv[0]);
    if (!ref) ref = argv[0];
    update_ref("refs/heads/master", ref);
    Index index = {0};
    checkout_commit(ref);
    write_index(&index);
}

int main(int argc, char **argv) {
    if (argc < 2) die("usage: minigt <command> [args]");
    const char *cmd = argv[1];
    int cmd_argc = argc - 2;
    char **cmd_argv = argv + 2;
    if (strcmp(cmd, "init") == 0) cmd_init(cmd_argc, cmd_argv);
    else if (strcmp(cmd, "add") == 0) cmd_add(cmd_argc, cmd_argv);
    else if (strcmp(cmd, "commit") == 0) cmd_commit(cmd_argc, cmd_argv);
    else if (strcmp(cmd, "checkout") == 0) cmd_checkout(cmd_argc, cmd_argv);
    else if (strcmp(cmd, "reset") == 0) cmd_reset(cmd_argc, cmd_argv);
    else die("unknown command");
    return 0;
}
